'use client'
import styles from './marketing-features.module.css'

type Feature = { icon: string; title: string; description: string }

const FEATURES: Feature[] = [
  {
    icon: '⚡',
    title: 'Signal-driven',
    description:
      'Preact Signals power every component. No useState, no re-renders, zero unnecessary DOM updates.',
  },
  {
    icon: '🎨',
    title: 'CSS-native',
    description:
      'Modern CSS only — @layer, @container, :has(), custom properties. No Tailwind, no CSS-in-JS.',
  },
  {
    icon: '♿',
    title: 'WCAG 2.1 AA',
    description:
      'Every component ships with correct ARIA roles, keyboard navigation, and focus management.',
  },
  {
    icon: '📋',
    title: 'Copy-paste model',
    description:
      'Components live in your project. You own the code. No vendor lock-in, no version surprises.',
  },
  {
    icon: '🤖',
    title: 'AI-first',
    description:
      'Machine-readable component manifests, MCP server, and Claude Code skills included out of the box.',
  },
  {
    icon: '🌗',
    title: 'Beautiful themes',
    description:
      'Light, dark, and warm themes ship as pure CSS. Scope any theme to any container with data-theme.',
  },
]

export function MarketingFeatures() {
  return (
    <section className={styles.root}>
      <div className={styles.header}>
        <h2 className={styles.heading}>Everything you need</h2>
        <p className={styles.subtitle}>
          cascivo is designed for developers who care about quality, performance, and
          maintainability.
        </p>
      </div>

      <div className={styles.gridOuter}>
        <div className={styles.grid}>
          {FEATURES.map((f) => (
            <article key={f.title} className={styles.cell} data-testid="feature-cell">
              <div className={styles.cellIcon} aria-hidden="true">
                {f.icon}
              </div>
              <h3 className={styles.cellTitle}>{f.title}</h3>
              <p className={styles.cellDescription}>{f.description}</p>
            </article>
          ))}
        </div>
      </div>
    </section>
  )
}

@layer cascivo.blocks.marketing-features {
  .root {
    padding-block: var(--cascivo-space-20);
    padding-inline: var(--cascivo-space-6);
    background: var(--cascivo-color-surface-raised);
  }

  .header {
    text-align: center;
    margin-block-end: var(--cascivo-space-12);
  }

  .heading {
    font-size: var(--cascivo-text-3xl);
    font-weight: var(--cascivo-font-bold);
    margin-block-end: var(--cascivo-space-3);
  }

  .subtitle {
    font-size: var(--cascivo-text-lg);
    color: var(--cascivo-color-foreground-muted);
    max-inline-size: 36rem;
    margin-inline: auto;
  }

  .gridOuter {
    container-type: inline-size;
    max-inline-size: 72rem;
    margin-inline: auto;
  }

  .grid {
    display: grid;
    grid-template-columns: 1fr;
    gap: var(--cascivo-space-8);
  }

  @container (min-inline-size: 40rem) {
    .grid {
      grid-template-columns: repeat(2, 1fr);
    }
  }

  @container (min-inline-size: 64rem) {
    .grid {
      grid-template-columns: repeat(3, 1fr);
    }
  }

  .cell {
    display: flex;
    flex-direction: column;
    gap: var(--cascivo-space-3);
  }

  .cellIcon {
    display: flex;
    align-items: center;
    justify-content: center;
    inline-size: 3rem;
    block-size: 3rem;
    border-radius: var(--cascivo-radius-md);
    background: var(--cascivo-color-accent-subtle);
    font-size: 1.5rem;
  }

  .cellTitle {
    font-size: var(--cascivo-text-lg);
    font-weight: var(--cascivo-font-semibold);
  }

  .cellDescription {
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-foreground-muted);
    line-height: var(--cascivo-leading-relaxed);
  }
}
